checker_dsl:
EXISTS (`taint flow path P`) {
  AND {
    EXISTS (`source node S`) {
      AND {
        (`S is an InsecureRandomnessSource`),
        EXISTS (`RandomDataSource RDS`) {
          AND {
            (`S's expression equals RDS's output expression`),
            NOT { (`RDS's source of randomness is a SafeRandomImplementation`) }
          }
        }
      }
    },
    EXISTS (`sink node T`) {
      OR {
        AND {
          (`T is an InsecureRandomnessSink`),
          (`T is a CredentialsSinkNode`)
        },
        AND {
          (`T is an InsecureRandomnessSink`),
          (`T is an ApiSinkNode`),
          (`T's expression is a SetCookieValue`)
        },
        AND {
          (`T is an InsecureRandomnessSink`),
          (`T's expression is a SensitiveExpr`)
        }
      }
    },
    (`P is a taint flow path from S to T`),
    EXISTS (`flow configuration C`) {
      EXISTS (`additional flow step from node N1 to node N2`) {
        OR {
          (`N1's expression equals N2's expression's operand in a BinaryExpr`),
          (`N1's expression equals N2's expression's operand in a UnaryExpr`),
          EXISTS (`MethodCall MC`, `string methodName`) {
            AND {
              (`MC's method has qualified name "org.owasp.esapi.Encoder.methodName"`),
              (`methodName matches pattern "encode%"`),
              (`N1's expression equals MC's argument 0`),
              (`N2's expression equals MC`)
            }
          },
          EXISTS (`Call C`) {
            OR {
              AND {
                (`C is a ClassInstanceExpr constructing java.util.UUID`),
                (`N1's expression equals C's argument`),
                (`N2's expression equals C`)
              },
              AND {
                (`C is a MethodCall to java.util.UUID.toString`),
                (`N1's expression equals C's qualifier`),
                (`N2's expression equals C`)
              }
            }
          }
        }
      }
    }
  }
}
